const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const contentType = trigger.content_type || '';
const rawSearch = trigger.search_term || '';
const rawLower = rawSearch.toLowerCase();
const httpSelf = this;
const userId = trigger.user_id || '';
const userFilter = userId ? '&user_id=eq.' + encodeURIComponent(userId) : '';

if (contentType === 'story_arc' || rawLower.indexOf('story arc') >= 0 || rawLower.indexOf('story arcs') >= 0 || trigger.operation === 'list_story_arcs') {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/story_arcs_v2?order=name.asc&select=id,name,description,discovery_question', headers });
  const arcs = Array.isArray(resp) ? resp : [];
  if (arcs.length === 0) { return [{ json: { found: false, result: 'No story arcs found.', content_type: 'story_arc_list', title: '', content_text: '', content_id: '' } }]; }
  const list = arcs.map((a, i) => (i + 1) + '. **' + a.name + '** \u2014 ' + a.description + (a.discovery_question ? ' [Discovery Question: ' + a.discovery_question + ']' : '')).join('\n');
  return [{ json: { found: true, result: 'Available story arcs:\n' + list, content_type: 'story_arc_list', title: 'Story Arcs', content_text: list, content_id: '' } }];
}

if (trigger.operation === 'list_projects' || rawLower.trim() === 'list_projects') {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?order=created_at.desc&select=id,title,genre_slug,created_at' + userFilter, headers });
  const projects = Array.isArray(resp) ? resp : [];
  if (projects.length === 0) { return [{ json: { found: false, result: 'No writing projects found.', content_type: 'project_list', title: '', content_text: '', content_id: '' } }]; }
  const list = projects.map((p, i) => (i + 1) + '. ' + p.title + ' (' + (p.genre_slug || 'no genre') + ') \u2014 created ' + new Date(p.created_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + projects.length + ' writing project(s):\n' + list, content_type: 'project_list', title: 'Writing Projects', content_text: list, content_id: '' } }];
}

const isListChapterOutlines = /\b(list|show|all)\b.*\bchapter\s+outline/i.test(rawSearch) || (contentType === 'chapter_outline');
if (isListChapterOutlines) {
  let coProject = null;
  const coSearchTerms = rawSearch.replace(/\b(list|show|all|chapter|outlines?|for|the|of|my)\b/gi, '').trim();
  if (coSearchTerms) {
    const coResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(coSearchTerms) + '*&select=id,title,outline' + userFilter + '&limit=1', headers });
    if (Array.isArray(coResp) && coResp.length > 0) coProject = coResp[0];
  }
  if (!coProject) {
    const coResp2 = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?outline=not.is.null&order=updated_at.desc&select=id,title,outline' + userFilter + '&limit=5', headers });
    const withCo = (coResp2 || []).filter(function(p) { return p.outline && p.outline.chapters && p.outline.chapters.some(function(ch) { return ch.chapter_outline && ch.chapter_outline.sub_chapters && ch.chapter_outline.sub_chapters.length > 0; }); });
    if (withCo.length > 0) coProject = withCo[0];
  }
  if (!coProject || !coProject.outline || !coProject.outline.chapters) {
    return [{ json: { found: false, result: 'No chapter outlines found. Create one with: "create a chapter outline for chapter N of [book title]"', content_type: 'chapter_outline_list', title: '', content_text: '', content_id: '' } }];
  }
  const chaptersWithOutlines = coProject.outline.chapters.filter(function(ch) { return ch.chapter_outline && ch.chapter_outline.sub_chapters && ch.chapter_outline.sub_chapters.length > 0; });
  if (chaptersWithOutlines.length === 0) {
    return [{ json: { found: false, result: 'No chapter outlines found for "' + coProject.title + '". The book outline exists with ' + coProject.outline.chapters.length + ' chapters, but none have detailed sub-chapter outlines yet.', content_type: 'chapter_outline_list', title: coProject.title, content_text: '', content_id: '' } }];
  }
  const coList = chaptersWithOutlines.map(function(ch) {
    const co = ch.chapter_outline;
    const subCount = co.sub_chapters.length;
    const arc = co.chapter_story_arc || 'not set';
    const allChs = coProject.outline.chapters;
    const chLbl = (ch === allChs[0] || ch.number === 0) ? 'Prologue' : (ch === allChs[allChs.length - 1] ? 'Epilogue' : 'Ch ' + ch.number);
    return '- **' + chLbl + ' \u2014 ' + (co.chapter_title || ch.title) + '**: ' + subCount + ' sub-chapters, arc: ' + arc;
  }).join('\n');
  return [{ json: { found: true, result: '"' + coProject.title + '" has ' + chaptersWithOutlines.length + ' chapter outline(s):\n' + coList + '\n\nChapters without outlines: ' + (coProject.outline.chapters.length - chaptersWithOutlines.length) + '. Use "create a chapter outline for chapter N" to add more.', content_type: 'chapter_outline_list', title: coProject.title, content_text: coList, content_id: coProject.id } }];
}

const isListOutlines = trigger.operation === 'list_outlines' || /\b(list|show|all)\b.*\boutline/i.test(rawSearch) || (contentType === 'outline' && /\b(list|show|all)\b/i.test(rawSearch)) || (contentType === 'outline' && /^\s*outlines?\s*$/i.test(rawSearch));
if (isListOutlines) {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?outline=not.is.null&order=updated_at.desc&select=id,title,genre_slug,status,chapter_count,outline,updated_at' + userFilter, headers });
  const projects = Array.isArray(resp) ? resp : [];
  const withOutlines = projects.filter(function(p) { return p.title && p.outline && typeof p.outline === 'object' && Object.keys(p.outline).length > 0; });
  if (withOutlines.length === 0) { return [{ json: { found: false, result: 'No outlines found.', content_type: 'outline_list', title: '', content_text: '', content_id: '' } }]; }
  const list = withOutlines.map((p, i) => (i + 1) + '. **' + p.title + '** (' + (p.genre_slug || 'no genre') + ') \u2014 ' + (p.status || 'outlined') + ', ' + (p.chapter_count || 0) + ' chapters \u2014 updated ' + new Date(p.updated_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + withOutlines.length + ' outline(s):\n' + list, content_type: 'outline_list', title: 'Story Outlines', content_text: list, content_id: '' } }];
}

const isOutlineVersions = trigger.operation === 'outline_versions' || /\b(version|versions|history)\b.*\boutline/i.test(rawSearch) || /\boutline\b.*\b(version|versions|history)\b/i.test(rawSearch);
if (isOutlineVersions) {
  const vSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','versions','history','show','list','for','get'].indexOf(w) === -1; }).slice(0, 4);
  let projectId = null; let projectTitle = '';
  for (const term of vSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1' + userFilter, headers });
    if (Array.isArray(pResp) && pResp.length > 0) { projectId = pResp[0].id; projectTitle = pResp[0].title; break; }
  }
  if (!projectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_version_list', title: '', content_text: '', content_id: '' } }]; }
  const verResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + projectId + '&order=version_number.desc&select=id,version_number,revision_note,created_at' + userFilter, headers });
  const versions = Array.isArray(verResp) ? verResp : [];
  if (versions.length === 0) { return [{ json: { found: true, result: 'No version history found for "' + projectTitle + '".', content_type: 'outline_version_list', title: projectTitle, content_text: '', content_id: '' } }]; }
  const vList = versions.map(function(v, i) { return (i + 1) + '. Version ' + v.version_number + ' \u2014 ' + new Date(v.created_at).toLocaleString() + (v.revision_note ? ' (' + v.revision_note + ')' : ''); }).join('\n');
  return [{ json: { found: true, result: 'Outline versions for "' + projectTitle + '":\n' + vList + '\n\nTo revert: "revert outline for ' + projectTitle + ' to version N"', content_type: 'outline_version_list', title: projectTitle, content_text: vList, content_id: '' } }];
}

const revertMatch = rawLower.match(/revert.*outline.*(?:to|version)\s*(\d+)/i) || (trigger.operation === 'revert_outline' ? [null, trigger.version_number] : null);
if (revertMatch) {
  const targetVersion = parseInt(revertMatch[1]);
  const rSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','revert','to','for','get','back'].indexOf(w) === -1 && !/^\d+$/.test(w); }).slice(0, 4);
  let rProjectId = null; let rProjectTitle = '';
  for (const term of rSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1' + userFilter, headers });
    if (Array.isArray(pResp) && pResp.length > 0) { rProjectId = pResp[0].id; rProjectTitle = pResp[0].title; break; }
  }
  if (!rProjectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_revert', title: '', content_text: '', content_id: '' } }]; }
  const vResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + rProjectId + '&version_number=eq.' + targetVersion + '&select=outline,version_number&limit=1' + userFilter, headers });
  if (!Array.isArray(vResp) || vResp.length === 0) { return [{ json: { found: false, result: 'Version ' + targetVersion + ' not found for "' + rProjectTitle + '".', content_type: 'outline_revert', title: rProjectTitle, content_text: '', content_id: '' } }]; }
  const oldOutline = vResp[0].outline;
  await httpSelf.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + rProjectId + userFilter, headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' }, body: { outline: oldOutline, updated_at: new Date().toISOString() } });
  const chars = (oldOutline.characters || []).map(function(c) { return c.name; }).join(', ');
  return [{ json: { found: true, result: 'Reverted "' + rProjectTitle + '" to version ' + targetVersion + '. Characters: ' + chars + '. Chapters: ' + (oldOutline.chapters || []).length, content_type: 'outline_revert', title: rProjectTitle, content_text: 'Reverted to version ' + targetVersion, content_id: rProjectId } }];
}

const stopWords = ['the', 'a', 'an', 'in', 'on', 'at', 'to', 'for', 'of', 'and', 'or', 'is', 'are', 'was', 'were', 'how', 'what', 'why', 'when', 'my', 'draft', 'about', 'called', 'titled', 'named', 'get', 'pull', 'up', 'blog', 'post', 'story', 'short', 'newsletter', 'chapter', 'report', 'research', 'all', 'chapters', 'from', 'project', 'retrieve', 'fetch', 'find', 'outline', 'outlines', 'list', 'show'];
const words = rawSearch.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && stopWords.indexOf(w) === -1; });
const searchTerms = words.slice(0, 4);

let title = ''; let contentText = ''; let storagePath = ''; let contentId = ''; let foundType = contentType;

async function searchProjectChapters(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug,outline&limit=5' + userFilter;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const projects = Array.isArray(resp) ? resp : [];
    if (projects.length > 0) {
      const project = projects[0];
      let epilogueNum = 999;
      if (project.outline && project.outline.chapters && project.outline.chapters.length > 0) {
        epilogueNum = project.outline.chapters[project.outline.chapters.length - 1].number;
      }
      project.epilogueNum = epilogueNum;
      delete project.outline;
      const chapUrl = supabaseUrl + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&content_type=eq.chapter&order=chapter_number.asc&select=id,title,content_type,status,chapter_number,created_at' + userFilter;
      const chapResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: chapUrl, headers });
      return { project, chapters: Array.isArray(chapResp) ? chapResp : [] };
    }
  }
  return null;
}

async function searchPublishedContent(type, terms) {
  for (const term of terms) {
    let url = supabaseUrl + '/rest/v1/published_content_v2?title=ilike.*' + encodeURIComponent(term) + '*&order=created_at.desc&limit=5' + userFilter;
    if (type) url += '&content_type=eq.' + type;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      return items.find(function(item) { const t = (item.title || '').toLowerCase(); return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2; }) || items[0];
    }
  }
  return null;
}

async function searchResearchReports(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/research_reports_v2?topic=ilike.*' + encodeURIComponent(term) + '*&order=updated_at.desc&limit=5' + userFilter;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      return items.find(function(item) { const t = (item.topic || '').toLowerCase(); return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2; }) || items[0];
    }
  }
  return null;
}

try {
  if (contentType === 'outline' || contentType === '' || rawSearch.toLowerCase().indexOf('outline') >= 0) {
    for (const term of searchTerms) {
      const url = supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug,outline,created_at&limit=5' + userFilter;
      const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
      const projects = Array.isArray(resp) ? resp : [];
      const match = projects.find(function(p) { return p.outline && Object.keys(p.outline).length > 0; });
      if (match) {
        const o = match.outline;
        const parts = [];
        parts.push('# Story Outline: ' + (o.title || match.title));
        if (o.premise) parts.push('\n## Premise\n' + o.premise);
        if (o.themes) parts.push('\n## Themes\n' + (Array.isArray(o.themes) ? o.themes.join(', ') : o.themes));
        if (o.characters) {
          parts.push('\n## Characters');
          o.characters.forEach(function(c) { parts.push('- **' + c.name + '** (' + c.role + '): ' + c.arc + (c.description ? ' \u2014 ' + c.description : '')); });
        }
        if (o.chapters) {
          parts.push('\n## Story Structure');
          o.chapters.forEach(function(ch, idx, arr) { var lbl = (idx === 0 ? 'Prologue' : (idx === arr.length - 1 ? 'Epilogue' : 'Ch ' + ch.number)); parts.push(lbl + '. **' + ch.title + '**: ' + ch.brief + (ch.arc_notes ? ' _[Arc: ' + ch.arc_notes + ']_' : '')); });
        }
        const outlineText = parts.join('\n');
        return [{ json: { found: true, title: o.title || match.title, content_text: outlineText, content_type: 'outline', content_id: match.id, result: 'Found outline: ' + (o.title || match.title) + ' (' + outlineText.length + ' chars)' } }];
      }
    }
    if (contentType === 'outline') { return [{ json: { found: false, result: 'No outline found for: ' + rawSearch, content_type: 'outline', title: '', content_text: '', content_id: '' } }]; }
  }

  if (contentType === '' || contentType === 'chapter') {
    const projectResult = await searchProjectChapters(searchTerms);
    if (projectResult) {
      const { project, chapters } = projectResult;
      if (chapters.length === 0) {
        if (project.genre_slug) {
          const fallbackUrl = supabaseUrl + '/rest/v1/published_content_v2?content_type=eq.chapter&genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&order=created_at.desc&limit=10&select=id,title,content_type,status,chapter_number,created_at' + userFilter;
          const fallbackResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: fallbackUrl, headers });
          const fallbackChapters = Array.isArray(fallbackResp) ? fallbackResp : [];
          if (fallbackChapters.length > 0) {
            const epN = project.epilogueNum || 999;
            const flist = fallbackChapters.map((c, i) => (i + 1) + '. ' + (c.chapter_number === 0 || !c.chapter_number ? 'Prologue' : (c.chapter_number === epN || c.chapter_number === 999 ? 'Epilogue' : 'Chapter ' + c.chapter_number)) + ': ' + (c.title || 'Untitled') + ' \u2014 ' + (c.status || 'draft') + ' [ID: ' + c.id + ']').join('\n');
            return [{ json: { found: true, result: 'Project: ' + project.title + '\nFound ' + fallbackChapters.length + ' chapter(s):\n' + flist, content_type: 'chapter_list', title: project.title, content_text: flist, content_id: '' } }];
          }
        }
        return [{ json: { found: false, result: 'Project "' + project.title + '" found but no chapters written yet.', content_type: 'chapter_list', title: project.title, content_text: '', content_id: '' } }];
      }
      const epNum = project.epilogueNum || 999;
      const list = chapters.map((c, i) => (i + 1) + '. ' + (c.chapter_number === 0 || !c.chapter_number ? 'Prologue' : (c.chapter_number === epNum || c.chapter_number === 999 ? 'Epilogue' : 'Chapter ' + c.chapter_number)) + ': ' + (c.title || 'Untitled') + ' \u2014 ' + (c.status || 'draft') + ' [ID: ' + c.id + ']').join('\n');
      return [{ json: { found: true, result: 'Project: ' + project.title + '\nFound ' + chapters.length + ' chapter(s):\n' + list, content_type: 'chapter_list', title: project.title, content_text: list, content_id: '' } }];
    }
  }

  if (contentType === 'research_report') {
    const item = await searchResearchReports(searchTerms);
    if (item) { title = item.topic || 'Research Report'; contentText = item.content || ''; contentId = item.id; }
  } else if (['short_story', 'blog_post', 'newsletter', 'chapter'].indexOf(contentType) >= 0) {
    const item = await searchPublishedContent(contentType, searchTerms);
    if (item) { title = item.title || 'Untitled'; contentText = item.content_text || ''; storagePath = item.storage_path || ''; contentId = item.id; }
  } else {
    var pcItem = await searchPublishedContent('', searchTerms);
    if (pcItem) { title = pcItem.title || 'Untitled'; contentText = pcItem.content_text || ''; storagePath = pcItem.storage_path || ''; contentId = pcItem.id; foundType = pcItem.content_type || 'unknown'; }
    else {
      var rrItem = await searchResearchReports(searchTerms);
      if (rrItem) { title = rrItem.topic || 'Research Report'; contentText = rrItem.content || ''; contentId = rrItem.id; foundType = 'research_report'; }
    }
  }

  if (contentText === '' && storagePath) {
    try {
      contentText = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/storage/v1/object/' + storagePath, headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }, returnFullResponse: false });
      if (typeof contentText !== 'string') contentText = JSON.stringify(contentText);
    } catch (e) { contentText = '[Error fetching from storage: ' + e.message + ']'; }
  }

  if (contentText === '' && title === '') {
    return [{ json: { found: false, result: 'No content found for: ' + rawSearch + ' (type: ' + (contentType || 'any') + '). Keywords: ' + searchTerms.join(', ') } }];
  }

  var maxLen = 100000;
  if (contentText.length > maxLen) contentText = contentText.substring(0, maxLen) + ' [Truncated]';

  return [{ json: { found: true, title: title, content_text: contentText, content_type: foundType, content_id: contentId, result: 'Found: ' + title + ' (' + foundType + ', ' + contentText.length + ' chars)' } }];
} catch (err) {
  return [{ json: { found: false, result: 'Error: ' + err.message } }];
}

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const contentType = trigger.content_type || '';
const rawSearch = trigger.search_term || '';
const rawLower = rawSearch.toLowerCase();
const httpSelf = this;
const userId = trigger.user_id || '';
const userFilter = userId ? '&user_id=eq.' + encodeURIComponent(userId) : '';

if (contentType === 'story_arc' || rawLower.indexOf('story arc') >= 0 || rawLower.indexOf('story arcs') >= 0 || trigger.operation === 'list_story_arcs') {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/story_arcs_v2?order=name.asc&select=id,name,description,discovery_question', headers });
  const arcs = Array.isArray(resp) ? resp : [];
  if (arcs.length === 0) { return [{ json: { found: false, result: 'No story arcs found.', content_type: 'story_arc_list', title: '', content_text: '', content_id: '' } }]; }
  const list = arcs.map((a, i) => (i + 1) + '. **' + a.name + '** \u2014 ' + a.description + (a.discovery_question ? ' [Discovery Question: ' + a.discovery_question + ']' : '')).join('\n');
  return [{ json: { found: true, result: 'Available story arcs:\n' + list, content_type: 'story_arc_list', title: 'Story Arcs', content_text: list, content_id: '' } }];
}

if (trigger.operation === 'list_projects' || rawLower.trim() === 'list_projects') {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?order=created_at.desc&select=id,title,genre_slug,created_at' + userFilter, headers });
  const projects = Array.isArray(resp) ? resp : [];
  if (projects.length === 0) { return [{ json: { found: false, result: 'No writing projects found.', content_type: 'project_list', title: '', content_text: '', content_id: '' } }]; }
  const list = projects.map((p, i) => (i + 1) + '. ' + p.title + ' (' + (p.genre_slug || 'no genre') + ') \u2014 created ' + new Date(p.created_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + projects.length + ' writing project(s):\n' + list, content_type: 'project_list', title: 'Writing Projects', content_text: list, content_id: '' } }];
}

const isListChapterOutlines = /\b(list|show|all)\b.*\bchapter\s+outline/i.test(rawSearch) || (contentType === 'chapter_outline');
if (isListChapterOutlines) {
  let coProject = null;
  const coSearchTerms = rawSearch.replace(/\b(list|show|all|chapter|outlines?|for|the|of|my)\b/gi, '').trim();
  if (coSearchTerms) {
    const coResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(coSearchTerms) + '*&select=id,title,outline' + userFilter + '&limit=1', headers });
    if (Array.isArray(coResp) && coResp.length > 0) coProject = coResp[0];
  }
  if (!coProject) {
    const coResp2 = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?outline=not.is.null&order=updated_at.desc&select=id,title,outline' + userFilter + '&limit=5', headers });
    const withCo = (coResp2 || []).filter(function(p) { return p.outline && p.outline.chapters && p.outline.chapters.some(function(ch) { return ch.chapter_outline && ch.chapter_outline.sub_chapters && ch.chapter_outline.sub_chapters.length > 0; }); });
    if (withCo.length > 0) coProject = withCo[0];
  }
  if (!coProject || !coProject.outline || !coProject.outline.chapters) {
    return [{ json: { found: false, result: 'No chapter outlines found. Create one with: "create a chapter outline for chapter N of [book title]"', content_type: 'chapter_outline_list', title: '', content_text: '', content_id: '' } }];
  }
  const chaptersWithOutlines = coProject.outline.chapters.filter(function(ch) { return ch.chapter_outline && ch.chapter_outline.sub_chapters && ch.chapter_outline.sub_chapters.length > 0; });
  if (chaptersWithOutlines.length === 0) {
    return [{ json: { found: false, result: 'No chapter outlines found for "' + coProject.title + '". The book outline exists with ' + coProject.outline.chapters.length + ' chapters, but none have detailed sub-chapter outlines yet.', content_type: 'chapter_outline_list', title: coProject.title, content_text: '', content_id: '' } }];
  }
  const coList = chaptersWithOutlines.map(function(ch) {
    const co = ch.chapter_outline;
    const subCount = co.sub_chapters.length;
    const arc = co.chapter_story_arc || 'not set';
    const allChs = coProject.outline.chapters;
    const chLbl = (ch === allChs[0] || ch.number === 0) ? 'Prologue' : (ch === allChs[allChs.length - 1] ? 'Epilogue' : 'Ch ' + ch.number);
    return '- **' + chLbl + ' \u2014 ' + (co.chapter_title || ch.title) + '**: ' + subCount + ' sub-chapters, arc: ' + arc;
  }).join('\n');
  return [{ json: { found: true, result: '"' + coProject.title + '" has ' + chaptersWithOutlines.length + ' chapter outline(s):\n' + coList + '\n\nChapters without outlines: ' + (coProject.outline.chapters.length - chaptersWithOutlines.length) + '. Use "create a chapter outline for chapter N" to add more.', content_type: 'chapter_outline_list', title: coProject.title, content_text: coList, content_id: coProject.id } }];
}

const isListOutlines = trigger.operation === 'list_outlines' || /\b(list|show|all)\b.*\boutline/i.test(rawSearch) || (contentType === 'outline' && /\b(list|show|all)\b/i.test(rawSearch)) || (contentType === 'outline' && /^\s*outlines?\s*$/i.test(rawSearch));
if (isListOutlines) {
  const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?outline=not.is.null&order=updated_at.desc&select=id,title,genre_slug,status,chapter_count,outline,updated_at' + userFilter, headers });
  const projects = Array.isArray(resp) ? resp : [];
  const withOutlines = projects.filter(function(p) { return p.title && p.outline && typeof p.outline === 'object' && Object.keys(p.outline).length > 0; });
  if (withOutlines.length === 0) { return [{ json: { found: false, result: 'No outlines found.', content_type: 'outline_list', title: '', content_text: '', content_id: '' } }]; }
  const list = withOutlines.map((p, i) => (i + 1) + '. **' + p.title + '** (' + (p.genre_slug || 'no genre') + ') \u2014 ' + (p.status || 'outlined') + ', ' + (p.chapter_count || 0) + ' chapters \u2014 updated ' + new Date(p.updated_at).toLocaleDateString()).join('\n');
  return [{ json: { found: true, result: 'Found ' + withOutlines.length + ' outline(s):\n' + list, content_type: 'outline_list', title: 'Story Outlines', content_text: list, content_id: '' } }];
}

const isOutlineVersions = trigger.operation === 'outline_versions' || /\b(version|versions|history)\b.*\boutline/i.test(rawSearch) || /\boutline\b.*\b(version|versions|history)\b/i.test(rawSearch);
if (isOutlineVersions) {
  const vSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','versions','history','show','list','for','get'].indexOf(w) === -1; }).slice(0, 4);
  let projectId = null; let projectTitle = '';
  for (const term of vSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1' + userFilter, headers });
    if (Array.isArray(pResp) && pResp.length > 0) { projectId = pResp[0].id; projectTitle = pResp[0].title; break; }
  }
  if (!projectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_version_list', title: '', content_text: '', content_id: '' } }]; }
  const verResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + projectId + '&order=version_number.desc&select=id,version_number,revision_note,created_at' + userFilter, headers });
  const versions = Array.isArray(verResp) ? verResp : [];
  if (versions.length === 0) { return [{ json: { found: true, result: 'No version history found for "' + projectTitle + '".', content_type: 'outline_version_list', title: projectTitle, content_text: '', content_id: '' } }]; }
  const vList = versions.map(function(v, i) { return (i + 1) + '. Version ' + v.version_number + ' \u2014 ' + new Date(v.created_at).toLocaleString() + (v.revision_note ? ' (' + v.revision_note + ')' : ''); }).join('\n');
  return [{ json: { found: true, result: 'Outline versions for "' + projectTitle + '":\n' + vList + '\n\nTo revert: "revert outline for ' + projectTitle + ' to version N"', content_type: 'outline_version_list', title: projectTitle, content_text: vList, content_id: '' } }];
}

const revertMatch = rawLower.match(/revert.*outline.*(?:to|version)\s*(\d+)/i) || (trigger.operation === 'revert_outline' ? [null, trigger.version_number] : null);
if (revertMatch) {
  const targetVersion = parseInt(revertMatch[1]);
  const rSearchTerms = rawLower.replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && ['the','outline','version','revert','to','for','get','back'].indexOf(w) === -1 && !/^\d+$/.test(w); }).slice(0, 4);
  let rProjectId = null; let rProjectTitle = '';
  for (const term of rSearchTerms) {
    const pResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title&limit=1' + userFilter, headers });
    if (Array.isArray(pResp) && pResp.length > 0) { rProjectId = pResp[0].id; rProjectTitle = pResp[0].title; break; }
  }
  if (!rProjectId) { return [{ json: { found: false, result: 'No project found matching: ' + rawSearch, content_type: 'outline_revert', title: '', content_text: '', content_id: '' } }]; }
  const vResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + rProjectId + '&version_number=eq.' + targetVersion + '&select=outline,version_number&limit=1' + userFilter, headers });
  if (!Array.isArray(vResp) || vResp.length === 0) { return [{ json: { found: false, result: 'Version ' + targetVersion + ' not found for "' + rProjectTitle + '".', content_type: 'outline_revert', title: rProjectTitle, content_text: '', content_id: '' } }]; }
  const oldOutline = vResp[0].outline;
  await httpSelf.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + rProjectId + userFilter, headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' }, body: { outline: oldOutline, updated_at: new Date().toISOString() } });
  const chars = (oldOutline.characters || []).map(function(c) { return c.name; }).join(', ');
  return [{ json: { found: true, result: 'Reverted "' + rProjectTitle + '" to version ' + targetVersion + '. Characters: ' + chars + '. Chapters: ' + (oldOutline.chapters || []).length, content_type: 'outline_revert', title: rProjectTitle, content_text: 'Reverted to version ' + targetVersion, content_id: rProjectId } }];
}

const stopWords = ['the', 'a', 'an', 'in', 'on', 'at', 'to', 'for', 'of', 'and', 'or', 'is', 'are', 'was', 'were', 'how', 'what', 'why', 'when', 'my', 'draft', 'about', 'called', 'titled', 'named', 'get', 'pull', 'up', 'blog', 'post', 'story', 'short', 'newsletter', 'chapter', 'report', 'research', 'all', 'chapters', 'from', 'project', 'retrieve', 'fetch', 'find', 'outline', 'outlines', 'list', 'show'];
const words = rawSearch.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/[ ]+/).filter(function(w) { return w.length > 2 && stopWords.indexOf(w) === -1; });
const searchTerms = words.slice(0, 4);

let title = ''; let contentText = ''; let storagePath = ''; let contentId = ''; let foundType = contentType;

async function searchProjectChapters(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug,outline&limit=5' + userFilter;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const projects = Array.isArray(resp) ? resp : [];
    if (projects.length > 0) {
      const project = projects[0];
      let epilogueNum = 999;
      if (project.outline && project.outline.chapters && project.outline.chapters.length > 0) {
        epilogueNum = project.outline.chapters[project.outline.chapters.length - 1].number;
      }
      project.epilogueNum = epilogueNum;
      delete project.outline;
      const chapUrl = supabaseUrl + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&content_type=eq.chapter&order=chapter_number.asc&select=id,title,content_type,status,chapter_number,created_at' + userFilter;
      const chapResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: chapUrl, headers });
      return { project, chapters: Array.isArray(chapResp) ? chapResp : [] };
    }
  }
  return null;
}

async function searchPublishedContent(type, terms) {
  for (const term of terms) {
    let url = supabaseUrl + '/rest/v1/published_content_v2?title=ilike.*' + encodeURIComponent(term) + '*&order=created_at.desc&limit=5' + userFilter;
    if (type) url += '&content_type=eq.' + type;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      return items.find(function(item) { const t = (item.title || '').toLowerCase(); return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2; }) || items[0];
    }
  }
  return null;
}

async function searchResearchReports(terms) {
  for (const term of terms) {
    const url = supabaseUrl + '/rest/v1/research_reports_v2?topic=ilike.*' + encodeURIComponent(term) + '*&order=updated_at.desc&limit=5' + userFilter;
    const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length > 0) {
      return items.find(function(item) { const t = (item.topic || '').toLowerCase(); return terms.filter(function(kw) { return t.indexOf(kw) >= 0; }).length >= 2; }) || items[0];
    }
  }
  return null;
}

try {
  if (contentType === 'outline' || contentType === '' || rawSearch.toLowerCase().indexOf('outline') >= 0) {
    for (const term of searchTerms) {
      const url = supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(term) + '*&select=id,title,genre_slug,outline,created_at&limit=5' + userFilter;
      const resp = await httpSelf.helpers.httpRequest({ method: 'GET', url, headers });
      const projects = Array.isArray(resp) ? resp : [];
      const match = projects.find(function(p) { return p.outline && Object.keys(p.outline).length > 0; });
      if (match) {
        const o = match.outline;
        const parts = [];
        parts.push('# Story Outline: ' + (o.title || match.title));
        if (o.premise) parts.push('\n## Premise\n' + o.premise);
        if (o.themes) parts.push('\n## Themes\n' + (Array.isArray(o.themes) ? o.themes.join(', ') : o.themes));
        if (o.characters) {
          parts.push('\n## Characters');
          o.characters.forEach(function(c) { parts.push('- **' + c.name + '** (' + c.role + '): ' + c.arc + (c.description ? ' \u2014 ' + c.description : '')); });
        }
        if (o.chapters) {
          parts.push('\n## Story Structure');
          o.chapters.forEach(function(ch, idx, arr) { var lbl = (idx === 0 ? 'Prologue' : (idx === arr.length - 1 ? 'Epilogue' : 'Ch ' + ch.number)); parts.push(lbl + '. **' + ch.title + '**: ' + ch.brief + (ch.arc_notes ? ' _[Arc: ' + ch.arc_notes + ']_' : '')); });
        }
        const outlineText = parts.join('\n');
        return [{ json: { found: true, title: o.title || match.title, content_text: outlineText, content_type: 'outline', content_id: match.id, result: 'Found outline: ' + (o.title || match.title) + ' (' + outlineText.length + ' chars)' } }];
      }
    }
    if (contentType === 'outline') { return [{ json: { found: false, result: 'No outline found for: ' + rawSearch, content_type: 'outline', title: '', content_text: '', content_id: '' } }]; }
  }

  if (contentType === '' || contentType === 'chapter') {
    const projectResult = await searchProjectChapters(searchTerms);
    if (projectResult) {
      const { project, chapters } = projectResult;
      if (chapters.length === 0) {
        if (project.genre_slug) {
          const fallbackUrl = supabaseUrl + '/rest/v1/published_content_v2?content_type=eq.chapter&genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&order=created_at.desc&limit=10&select=id,title,content_type,status,chapter_number,created_at' + userFilter;
          const fallbackResp = await httpSelf.helpers.httpRequest({ method: 'GET', url: fallbackUrl, headers });
          const fallbackChapters = Array.isArray(fallbackResp) ? fallbackResp : [];
          if (fallbackChapters.length > 0) {
            const epN = project.epilogueNum || 999;
            const flist = fallbackChapters.map((c, i) => (i + 1) + '. ' + (c.chapter_number === 0 || !c.chapter_number ? 'Prologue' : (c.chapter_number === epN || c.chapter_number === 999 ? 'Epilogue' : 'Chapter ' + c.chapter_number)) + ': ' + (c.title || 'Untitled') + ' \u2014 ' + (c.status || 'draft') + ' [ID: ' + c.id + ']').join('\n');
            return [{ json: { found: true, result: 'Project: ' + project.title + '\nFound ' + fallbackChapters.length + ' chapter(s):\n' + flist, content_type: 'chapter_list', title: project.title, content_text: flist, content_id: '' } }];
          }
        }
        return [{ json: { found: false, result: 'Project "' + project.title + '" found but no chapters written yet.', content_type: 'chapter_list', title: project.title, content_text: '', content_id: '' } }];
      }
      const epNum = project.epilogueNum || 999;
      const list = chapters.map((c, i) => (i + 1) + '. ' + (c.chapter_number === 0 || !c.chapter_number ? 'Prologue' : (c.chapter_number === epNum || c.chapter_number === 999 ? 'Epilogue' : 'Chapter ' + c.chapter_number)) + ': ' + (c.title || 'Untitled') + ' \u2014 ' + (c.status || 'draft') + ' [ID: ' + c.id + ']').join('\n');
      return [{ json: { found: true, result: 'Project: ' + project.title + '\nFound ' + chapters.length + ' chapter(s):\n' + list, content_type: 'chapter_list', title: project.title, content_text: list, content_id: '' } }];
    }
  }

  if (contentType === 'research_report') {
    const item = await searchResearchReports(searchTerms);
    if (item) { title = item.topic || 'Research Report'; contentText = item.content || ''; contentId = item.id; }
  } else if (['short_story', 'blog_post', 'newsletter', 'chapter'].indexOf(contentType) >= 0) {
    const item = await searchPublishedContent(contentType, searchTerms);
    if (item) { title = item.title || 'Untitled'; contentText = item.content_text || ''; storagePath = item.storage_path || ''; contentId = item.id; }
  } else {
    var pcItem = await searchPublishedContent('', searchTerms);
    if (pcItem) { title = pcItem.title || 'Untitled'; contentText = pcItem.content_text || ''; storagePath = pcItem.storage_path || ''; contentId = pcItem.id; foundType = pcItem.content_type || 'unknown'; }
    else {
      var rrItem = await searchResearchReports(searchTerms);
      if (rrItem) { title = rrItem.topic || 'Research Report'; contentText = rrItem.content || ''; contentId = rrItem.id; foundType = 'research_report'; }
    }
  }

  if (contentText === '' && storagePath) {
    try {
      contentText = await httpSelf.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/storage/v1/object/' + storagePath, headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }, returnFullResponse: false });
      if (typeof contentText !== 'string') contentText = JSON.stringify(contentText);
    } catch (e) { contentText = '[Error fetching from storage: ' + e.message + ']'; }
  }

  if (contentText === '' && title === '') {
    return [{ json: { found: false, result: 'No content found for: ' + rawSearch + ' (type: ' + (contentType || 'any') + '). Keywords: ' + searchTerms.join(', ') } }];
  }

  var maxLen = 100000;
  if (contentText.length > maxLen) contentText = contentText.substring(0, maxLen) + ' [Truncated]';

  return [{ json: { found: true, title: title, content_text: contentText, content_type: foundType, content_id: contentId, result: 'Found: ' + title + ' (' + foundType + ', ' + contentText.length + ' chars)' } }];
} catch (err) {
  return [{ json: { found: false, result: 'Error: ' + err.message } }];
}
